/**
 * MedX skeleton runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Loading placeholders for tables, cards, and detail panels during data fetches.
 */
const SKELETON_PRESETS = Object.freeze({
  text: { height: "h-4", width: "w-full", rounded: "rounded" },
  title: { height: "h-6", width: "w-3/4", rounded: "rounded" },
  avatar: { height: "h-10", width: "w-10", rounded: "rounded-full" },
  button: { height: "h-9", width: "w-24", rounded: "rounded-md" },
  card: { height: "h-32", width: "w-full", rounded: "rounded-lg" },
  tableRow: { height: "h-12", width: "w-full", rounded: "rounded-none" },
});

const skeletonGroups = new Map();

function createSkeletonElement(preset, overrides = {}) {
  const base = SKELETON_PRESETS[preset] ?? SKELETON_PRESETS.text;
  return {
    preset,
    ...base,
    ...overrides,
    animate: overrides.animate ?? "animate-pulse",
    ariaHidden: true,
  };
}

function createSkeletonGroup(id, layout) {
  const elements = layout.map((item, index) => ({
    id: `${id}-el-${index}`,
    ...createSkeletonElement(item.preset, item.overrides ?? {}),
  }));
  const group = {
    id,
    elements,
    visible: true,
    createdAt: Date.now(),
    layoutName: layout.name ?? "custom",
  };
  skeletonGroups.set(id, group);
  return group;
}

const LAYOUTS = Object.freeze({
  kpiCard: [
    { preset: "text", overrides: { width: "w-1/2" } },
    { preset: "title" },
    { preset: "text", overrides: { width: "w-1/3" } },
  ],
  tablePage: Array.from({ length: 8 }, () => ({ preset: "tableRow" })),
  detailPanel: [
    { preset: "avatar" },
    { preset: "title" },
    { preset: "text" },
    { preset: "text", overrides: { width: "w-5/6" } },
    { preset: "text", overrides: { width: "w-2/3" } },
    { preset: "button" },
  ],
  inventoryGrid: Array.from({ length: 6 }, () => ({ preset: "card" })),
});

function hideSkeletonGroup(id) {
  const group = skeletonGroups.get(id);
  if (!group) return false;
  group.visible = false;
  group.hiddenAt = Date.now();
  group.durationMs = group.hiddenAt - group.createdAt;
  return true;
}

function getSkeletonMetrics() {
  const groups = Array.from(skeletonGroups.values());
  return {
    totalGroups: groups.length,
    visible: groups.filter((g) => g.visible).length,
    totalElements: groups.reduce((sum, g) => sum + g.elements.length, 0),
    avgDurationMs:
      groups.filter((g) => g.durationMs != null).reduce((sum, g) => sum + g.durationMs, 0) /
        (groups.filter((g) => g.durationMs != null).length || 1),
  };
}

async function runMedxSkeleton() {
  console.log("[medx:ui:skeleton] runtime initialized");
  console.log(`[medx:ui:skeleton] presets=${Object.keys(SKELETON_PRESETS).length} layouts=${Object.keys(LAYOUTS).length}`);

  createSkeletonGroup("dashboard-kpi", LAYOUTS.kpiCard);
  createSkeletonGroup("inventory-table", LAYOUTS.tablePage);
  createSkeletonGroup("shipment-detail", LAYOUTS.detailPanel);
  createSkeletonGroup("inventory-grid", LAYOUTS.inventoryGrid);

  await new Promise((resolve) => setTimeout(resolve, 120));
  hideSkeletonGroup("dashboard-kpi");
  hideSkeletonGroup("inventory-table");

  const metrics = getSkeletonMetrics();
  console.log(`[medx:ui:skeleton] groups=${metrics.totalGroups} elements=${metrics.totalElements}`);
  console.log(`[medx:ui:skeleton] visible=${metrics.visible} avgDurationMs=${Math.round(metrics.avgDurationMs)}`);
  console.log("[medx:ui:skeleton] bootstrap complete");
}

module.exports = runMedxSkeleton;
